import * as fs from 'fs';

interface EnvConfig {
  [key: string]: string | number | boolean | undefined;
}

function parseValue(value: string): string | number | boolean {
  const trimmed = value.trim();

  // Remove quotes if present
  let unquoted = trimmed;
  if ((trimmed.startsWith('"') && trimmed.endsWith('"')) ||
      (trimmed.startsWith("'") && trimmed.endsWith("'"))) {
    unquoted = trimmed.slice(1, -1);
  }

  // Parse boolean
  if (unquoted.toLowerCase() === 'true') return true;
  if (unquoted.toLowerCase() === 'false') return false;

  // Parse number
  if (!isNaN(Number(unquoted)) && unquoted !== '') {
    return Number(unquoted);
  }

  // Return as string
  return unquoted;
}

function loadEnv(filePath: string, required: string[] = []): EnvConfig {
  const config: EnvConfig = { ...process.env };

  try {
    const fileContent = fs.readFileSync(filePath, 'utf-8');
    const lines = fileContent.split('\n');

    for (const line of lines) {
      const trimmedLine = line.trim();

      // Skip empty lines and comments
      if (!trimmedLine || trimmedLine.startsWith('#')) {
        continue;
      }

      const equalIndex = trimmedLine.indexOf('=');
      if (equalIndex === -1) continue;

      const key = trimmedLine.substring(0, equalIndex).trim();
      const value = trimmedLine.substring(equalIndex + 1);

      if (key) {
        config[key] = parseValue(value);
      }
    }
  } catch (error) {
    // If file doesn't exist, continue with empty config
    if (!(error instanceof Error && (error as NodeJS.ErrnoException).code === 'ENOENT')) {
      throw error;
    }
  }

  // Check required variables
  for (const requiredKey of required) {
    if (!(requiredKey in config)) {
      throw new Error(`Missing required environment variable: ${requiredKey}`);
    }
  }

  return config;
}

