type ErrorFirstCallback<T> = (err: Error | null, result?: T) => void;

function promisify<T>(
  fn: (...args: [...any[], ErrorFirstCallback<T>]) => void
): (...args: any[]) => Promise<T> {
  // Return a function that:
  // 1. Accepts the leading arguments (without the callback)
  // 2. Returns a new Promise
  // 3. Calls fn with those arguments plus a callback that resolves/rejects
  // 4. Preserves `this` using the caller's context
}

solution:
type ErrorFirstCallback<T> = (err: Error | null, result?: T) => void;

function promisify<T>(
  fn: (...args: [...any[], ErrorFirstCallback<T>]) => void
): (...args: any[]) => Promise<T> {
  return function (this: unknown, ...args: any[]): Promise<T> {
    return new Promise<T>((resolve, reject) => {
      fn.call(this, ...args, (err: Error | null, result?: T) => {
        if (err) {
          reject(err);
        } else {
          resolve(result as T);
        }
      });
    });
  };
}

