  // Return a wrapper that resets a timer on every call
  // and invokes fn only after delayMs of inactivity
}

function throttle<T extends (...args: any[]) => void>(fn: T, intervalMs: number): (...args: Parameters<T>) => void {
  // Return a wrapper that invokes fn immediately on the first call,
  // then ignores calls until intervalMs has passed
}

solution:
function debounce<T extends (...args: any[]) => void>(fn: T, delayMs: number): (...args: Parameters<T>) => void {
  let timer: ReturnType<typeof setTimeout> | null = null;

  return function (this: unknown, ...args: Parameters<T>): void {
    if (timer !== null) {
      clearTimeout(timer);
    }
    timer = setTimeout(() => {
      timer = null;
      fn.apply(this, args);
    }, delayMs);
  };
}

function throttle<T extends (...args: any[]) => void>(fn: T, intervalMs: number): (...args: Parameters<T>) => void {
  let onCooldown = false;

  return function (this: unknown, ...args: Parameters<T>): void {
    if (onCooldown) return;
    onCooldown = true;
    fn.apply(this, args);
    setTimeout(() => {
      onCooldown = false;
    }, intervalMs);
  };
}

