type QueryParams = Record<string, string | string[]>;

function decodeQueryComponent(value: string): string {
  return decodeURIComponent(value.replace(/\+/g, ' '));
}

function parseQueryString(url: string): QueryParams {
  const result: QueryParams = {};

  const questionMarkIndex = url.indexOf('?');
  if (questionMarkIndex === -1) return result;

  const queryString = url.slice(questionMarkIndex + 1);
  if (!queryString) return result;

  const pairs = queryString.split('&').filter(Boolean);

  for (const pair of pairs) {
    const equalIndex = pair.indexOf('=');
    const rawKey = equalIndex === -1 ? pair : pair.slice(0, equalIndex);
    const rawValue = equalIndex === -1 ? '' : pair.slice(equalIndex + 1);

    const key = decodeQueryComponent(rawKey);
    const value = decodeQueryComponent(rawValue);

    if (key in result) {
      const existing = result[key];
      if (Array.isArray(existing)) {
        existing.push(value);
      } else {
        result[key] = [existing, value];
      }
    } else {
      result[key] = value;
    }
  }

  return result;
}

