    if (!fs.existsSync(destinationDir)) {
      fs.mkdirSync(destinationDir, { recursive: true });
    }
  }

  async upload(
    readStream: NodeJS.ReadableStream,
    filename: string,
    maxSize: number,
    allowedTypes: string[],
    onProgress?: (progress: UploadProgress) => void
  ): Promise<UploadResult> {
    const startTime = Date.now();
    const filepath = path.join(this.destinationDir, filename);
    const writeStream = fs.createWriteStream(filepath);
    const hash = crypto.createHash('sha256');

    let bytesUploaded = 0;
    let totalBytes = 0;

    return new Promise((resolve, reject) => {
      // Handle stream errors
      readStream.on('error', (err) => {
        writeStream.destroy();
        fs.unlink(filepath, () => {});
        reject(err);
      });

      writeStream.on('error', (err) => {
        readStream.destroy();
        fs.unlink(filepath, () => {});
        reject(err);
      });

      // Track data and calculate hash
      readStream.on('data', (chunk: Buffer) => {
        bytesUploaded += chunk.length;

        // Check size limit during upload
        if (bytesUploaded > maxSize) {
          readStream.destroy();
          writeStream.destroy();
          fs.unlink(filepath, () => {});
          reject(new Error(`File size exceeds maximum of ${maxSize} bytes`));
          return;
        }

        hash.update(chunk);

        // Emit progress
        if (totalBytes === 0) {
          totalBytes = bytesUploaded;
        }

        if (onProgress) {
          onProgress({
            bytesUploaded,
            totalBytes: bytesUploaded,
            percentage: totalBytes > 0 ? (bytesUploaded / totalBytes) * 100 : 0
          });
        }
      });

      writeStream.on('finish', () => {
        const stats = fs.statSync(filepath);
        const duration = Date.now() - startTime;
        const fileHash = hash.digest('hex');

        // Validate file type if needed (would require additional metadata)
        resolve({
          filename,
          size: stats.size,
          hash: fileHash,
          duration
        });
      });

      // Pipe stream through write
      readStream.pipe(writeStream);
    });
  }
}

description.en:
Implement a job queue system that executes jobs with configurable concurrency limits and supports job prioritization.

**Requirements:**
- Create a `JobQueue` class that manages asynchronous job execution
- Support configurable concurrency level (max parallel jobs)
- Implement priority queue (jobs with higher priority execute first)
- Track job status (pending, running, completed, failed)
- Support job retries with exponential backoff
- Emit events for job lifecycle (started, completed, failed, retried)
- Provide statistics (queued, running, completed, failed counts)

**Function Signature:**
typescript
interface Job<T = any> {
  id: string;
  priority: number;
  task: () => Promise<T>;
  maxRetries: number;
  retryCount?: number;
}

interface JobStats {
  queued: number;
  running: number;
  completed: number;
  failed: number;
}

class JobQueue {
  constructor(concurrency: number);
  enqueue<T>(job: Job<T>): Promise<T>;
  getStats(): JobStats;
  on(event: 'started' | 'completed' | 'failed' | 'retried', callback: Function): void;
}


**Example:**
- Create queue with concurrency of 2
- Enqueue 5 jobs with different priorities
- Only 2 jobs run simultaneously
- Job with priority 10 executes before job with priority 5
- Failed job retries with exponential backoff (1s, 2s, 4s)
- Event emitted: `'completed'` when job finishes, `'failed'` after max retries exceeded

**Edge cases:**
- Multiple jobs with the same priority must execute in FIFO order (insertion order), not an arbitrary order
- A failed job (after exhausting retries) must not stop the queue from processing subsequent jobs
- Calling `getStats()` while jobs are actively running/retrying must return accurate, up-to-date counts
- A newly enqueued high-priority job should be picked up ahead of already-queued lower-priority jobs, even if they were added earlier

