interface Job<T = any> {
  id: string;
  priority: number;
  task: () => Promise<T>;
  maxRetries: number;
  retryCount?: number;
}

interface JobStats {
  queued: number;
  running: number;
  completed: number;
  failed: number;
}

type EventCallback = (jobId: string, error?: Error) => void;

class JobQueue {
  private concurrency: number;
  private queue: Job[] = [];
  private running: Set<string> = new Set();
  private completed: Set<string> = new Set();
  private failed: Set<string> = new Set();
  private eventListeners: Map<string, EventCallback[]> = new Map();
  private jobPromises: Map<string, { resolve: Function; reject: Function }> = new Map();
  private processing: boolean = false;

  constructor(concurrency: number) {
    this.concurrency = concurrency;
  }

  enqueue<T>(job: Job<T>): Promise<T> {
    job.retryCount = job.retryCount || 0;
    this.queue.push(job);

    // Sort by priority (higher first)
    this.queue.sort((a, b) => b.priority - a.priority);

    return new Promise((resolve, reject) => {
      this.jobPromises.set(job.id, { resolve, reject });
      this.processQueue();
    });
  }

  private async processQueue(): Promise<void> {
    if (this.processing) return;
    this.processing = true;

    while (this.queue.length > 0 || this.running.size > 0) {
      // Fill available slots
      while (this.running.size < this.concurrency && this.queue.length > 0) {
        const job = this.queue.shift()!;
        this.running.add(job.id);

        this.executeJob(job).catch(() => {});
      }

      // Wait for at least one job to complete
      if (this.running.size > 0) {
        await new Promise(resolve => setTimeout(resolve, 100));
      }
    }

    this.processing = false;
  }

  private async executeJob(job: Job): Promise<void> {
    try {
      this.emit('started', job.id);
      const result = await job.task();

      this.running.delete(job.id);
      this.completed.add(job.id);
      this.emit('completed', job.id);

      const promise = this.jobPromises.get(job.id);
      if (promise) {
        promise.resolve(result);
        this.jobPromises.delete(job.id);
      }
    } catch (error) {
      this.running.delete(job.id);

      if (job.retryCount! < job.maxRetries) {
        job.retryCount!++;
        const delay = Math.pow(2, job.retryCount! - 1) * 1000;

        this.emit('retried', job.id);

        setTimeout(() => {
          this.queue.push(job);
          this.queue.sort((a, b) => b.priority - a.priority);
          this.processQueue();
        }, delay);
      } else {
        this.failed.add(job.id);
        this.emit('failed', job.id, error as Error);

        const promise = this.jobPromises.get(job.id);
        if (promise) {
          promise.reject(error);
          this.jobPromises.delete(job.id);
        }
      }
    }
  }

  getStats(): JobStats {
    return {
      queued: this.queue.length,
      running: this.running.size,
      completed: this.completed.size,
      failed: this.failed.size
    };
  }

  on(event: 'started' | 'completed' | 'failed' | 'retried', callback: EventCallback): void {
    if (!this.eventListeners.has(event)) {
      this.eventListeners.set(event, []);
    }
    this.eventListeners.get(event)!.push(callback);
  }

  private emit(event: string, jobId: string, error?: Error): void {
    const callbacks = this.eventListeners.get(event) || [];
    callbacks.forEach(callback => callback(jobId, error));
  }
}

