solution:
type RateLimiterConfig = {
  capacity: number;
  refillRate: number;
  key?: (req: any) => string;
};

type TokenBucket = {
  tokens: number;
  lastRefillTime: number;
};

function createRateLimiter(config: RateLimiterConfig) {
  const buckets = new Map<string, TokenBucket>();
  const defaultConfig = {
    key: (req: any) => req.ip || 'default',
    ...config
  };

  return (req: any, res: any, next: () => void) => {
    const clientKey = defaultConfig.key(req);
    const now = Date.now();

    // Get or create bucket
    if (!buckets.has(clientKey)) {
      buckets.set(clientKey, {
        tokens: defaultConfig.capacity,
        lastRefillTime: now
      });
    }

    const bucket = buckets.get(clientKey)!;

    // Calculate tokens to add
    const timePassed = (now - bucket.lastRefillTime) / 1000; // convert to seconds
    const tokensToAdd = timePassed * defaultConfig.refillRate;
    bucket.tokens = Math.min(defaultConfig.capacity, bucket.tokens + tokensToAdd);
    bucket.lastRefillTime = now;

    // Check if request can proceed
    if (bucket.tokens >= 1) {
      bucket.tokens -= 1;
      next();
    } else {
      res.statusCode = 429;
      res.setHeader('Retry-After', Math.ceil(1 / defaultConfig.refillRate));
      res.end('Too many requests');
    }
  };
}

