declare function verifyToken(token: string, secret: string): { userId: string; [key: string]: any };

interface AuthMiddlewareOptions {
  secret: string;
  optional?: boolean;
}

function createAuthMiddleware(
  options: AuthMiddlewareOptions
): (req: any, res: any, next: (err?: any) => void) => void {
  return (req, res, next) => {
    const header = req.headers?.authorization as string | undefined;

    if (!header) {
      if (options.optional) {
        return next();
      }
      res.writeHead(401, { 'Content-Type': 'application/json' });
      return res.end(JSON.stringify({ error: 'Unauthorized' }));
    }

    const [scheme, token] = header.split(' ');
    if (scheme !== 'Bearer' || !token) {
      res.writeHead(401, { 'Content-Type': 'application/json' });
      return res.end(JSON.stringify({ error: 'Unauthorized' }));
    }

    try {
      const payload = verifyToken(token, options.secret);
      req.user = payload;
      next();
    } catch {
      // Never leak the internal verification error (e.g. exact expiry reason,
      // signature details) to the client - always return a generic 401
      res.writeHead(401, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'Unauthorized' }));
    }
  };
}

