interface Rec { id: number; [key: string]: any; }
interface PaginationParams { cursor?: number; limit: number; }
interface PaginationResult<T> { items: T[]; nextCursor: number | null; hasMore: boolean; }

function paginate<T extends Rec>(records: T[], params: PaginationParams): PaginationResult<T> {
  const { cursor, limit } = params;

  // Records past the cursor - relies on records being sorted ascending by id
  const startIndex = cursor === undefined
    ? 0
    : records.findIndex((r) => r.id > cursor);

  if (startIndex === -1) {
    // No records with id > cursor at all
    return { items: [], nextCursor: null, hasMore: false };
  }

  const page = records.slice(startIndex, startIndex + limit);
  const hasMore = startIndex + limit < records.length;
  const nextCursor = page.length > 0 ? page[page.length - 1].id : null;

  return {
    items: page,
    nextCursor: hasMore ? nextCursor : null,
    hasMore,
  };
}

