type FieldRule = { type: 'string' | 'number' | 'boolean'; required?: boolean; min?: number; max?: number };
type Schema = Record<string, FieldRule>;

function validateField(field: string, value: unknown, rule: FieldRule): { field: string; message: string } | null {
  const isMissing = value === undefined || value === null;

  if (isMissing) {
    if (rule.required) {
      return { field, message: `${field} is required` };
    }
    return null;
  }

  if (typeof value !== rule.type) {
    return { field, message: `${field} must be of type ${rule.type}` };
  }

  if (rule.type === 'string' && typeof value === 'string') {
    if (rule.min !== undefined && value.length < rule.min) {
      return { field, message: `${field} must be at least ${rule.min} characters` };
    }
    if (rule.max !== undefined && value.length > rule.max) {
      return { field, message: `${field} must be at most ${rule.max} characters` };
    }
  }

  if (rule.type === 'number' && typeof value === 'number') {
    if (rule.min !== undefined && value < rule.min) {
      return { field, message: `${field} must be at least ${rule.min}` };
    }
    if (rule.max !== undefined && value > rule.max) {
      return { field, message: `${field} must be at most ${rule.max}` };
    }
  }

  return null;
}

function validateBody(schema: Schema): (req: any, res: any, next: (err?: any) => void) => void {
  return (req, res, next) => {
    const body = req.body || {};
    const errors: { field: string; message: string }[] = [];

    for (const [field, rule] of Object.entries(schema)) {
      const error = validateField(field, body[field], rule);
      if (error) errors.push(error);
    }

    if (errors.length > 0) {
      res.writeHead(400, { 'Content-Type': 'application/json' });
      return res.end(JSON.stringify({ errors }));
    }

    next();
  };
}

