import * as http from 'http';

interface GracefulServerOptions {
  forceExitMs?: number;
}

function createGracefulServer(
  requestListener: (req: any, res: any) => void,
  options: GracefulServerOptions = {}
): { server: http.Server; shutdown: () => Promise<void> } {
  const forceExitMs = options.forceExitMs ?? 30000;
  let inFlight = 0;
  let shuttingDown = false;
  let shutdownPromise: Promise<void> | null = null;

  const server = http.createServer((req, res) => {
    if (shuttingDown) {
      res.writeHead(503, { 'Connection': 'close' });
      res.end('Server is shutting down');
      return;
    }

    inFlight++;
    res.on('finish', () => {
      inFlight--;
    });

    requestListener(req, res);
  });

  const shutdown = (): Promise<void> => {
    if (shutdownPromise) return shutdownPromise;

    shuttingDown = true;
    console.log('Shutdown initiated, draining in-flight requests...');

    shutdownPromise = new Promise((resolve) => {
      server.close(() => {
        // server.close's callback fires once all *connections* are closed,
        // but we track logical request completion via inFlight for clarity
      });

      let resolved = false;
      const finish = (forced: boolean) => {
        if (resolved) return;
        resolved = true;
        clearInterval(pollInterval);
        clearTimeout(forceTimer);
        console.log(forced ? 'Shutdown forced after timeout' : 'Shutdown completed gracefully');
        resolve();
      };

      const pollInterval = setInterval(() => {
        if (inFlight === 0) {
          finish(false);
        }
      }, 50);

      const forceTimer = setTimeout(() => {
        finish(true);
      }, forceExitMs);

      if (inFlight === 0) {
        finish(false);
      }
    });

    return shutdownPromise;
  };

  return { server, shutdown };
}

