type CircuitState = 'CLOSED' | 'OPEN' | 'HALF_OPEN';

interface CircuitBreakerOptions {
  failureThreshold: number;
  timeout: number;
  resetTimeout: number;
  successThreshold?: number;
}

class CircuitBreaker<T> {
  private state: CircuitState = 'CLOSED';
  private failureCount: number = 0;
  private successCount: number = 0;
  private lastFailureTime: number | null = null;
  private fn: () => Promise<T>;
  private options: CircuitBreakerOptions;
  private fallback: (() => Promise<T>) | null = null;

  constructor(fn: () => Promise<T>, options: CircuitBreakerOptions) {
    this.fn = fn;
    this.options = {
      ...options,
      successThreshold: options.successThreshold || 2,
    };
  }

  setFallback(fn: () => Promise<T>): void {
    this.fallback = fn;
  }

  async execute(): Promise<T> {
    if (this.state === 'OPEN') {
      if (this.shouldAttemptReset()) {
        this.state = 'HALF_OPEN';
      } else {
        if (this.fallback) {
          return this.fallback();
        }
        throw new Error('Circuit breaker is OPEN');
      }
    }

    try {
      const result = await this.executeWithTimeout();
      this.onSuccess();
      return result;
    } catch (error) {
      this.onFailure();
      throw error;
    }
  }

  private executeWithTimeout(): Promise<T> {
    return Promise.race([
      this.fn(),
      new Promise<T>((_, reject) =>
        setTimeout(
          () => reject(new Error('Circuit breaker timeout')),
          this.options.timeout
        )
      ),
    ]);
  }

  private onFailure(): void {
    this.failureCount++;
    this.lastFailureTime = Date.now();

    if (this.state === 'HALF_OPEN') {
      this.state = 'OPEN';
      this.successCount = 0;
    } else if (this.failureCount >= this.options.failureThreshold) {
      this.state = 'OPEN';
    }
  }

  private onSuccess(): void {
    this.failureCount = 0;

    if (this.state === 'HALF_OPEN') {
      this.successCount++;
      if (this.successCount >= (this.options.successThreshold || 2)) {
        this.state = 'CLOSED';
        this.successCount = 0;
      }
    }
  }

  private shouldAttemptReset(): boolean {
    return (
      this.lastFailureTime !== null &&
      Date.now() - this.lastFailureTime >= this.options.resetTimeout
    );
  }

  reset(): void {
    this.state = 'CLOSED';
    this.failureCount = 0;
    this.successCount = 0;
    this.lastFailureTime = null;
  }

  getState(): CircuitState {
    return this.state;
  }
}

