import { Transform, TransformOptions, TransformCallback } from 'stream';

class LineCounter extends Transform {
  private count: number = 0;
  private buffer: string = '';

  constructor(options?: TransformOptions) {
    super(options);
  }

  get lineCount(): number {
    return this.count;
  }

  _transform(chunk: Buffer, encoding: BufferEncoding, callback: TransformCallback): void {
    const text = this.buffer + chunk.toString('utf-8');
    const lines = text.split('\n');

    // The last element is either an empty string (chunk ended exactly on a newline)
    // or a partial line to carry over to the next chunk - either way it's not a
    // complete line yet, so don't count it here.
    this.buffer = lines.pop() as string;
    this.count += lines.length;

    // Pass the original chunk through unchanged - this is a pass-through transform,
    // counting is a side effect, not a data mutation.
    this.push(chunk);

    // Only call back once we're fully done processing this chunk synchronously;
    // this is what allows Node's internal buffering to correctly throttle the
    // upstream source when the downstream consumer is slow.
    callback();
  }

  _flush(callback: TransformCallback): void {
    if (this.buffer.length > 0) {
      this.count += 1;
    }
    callback();
  }
}

