import cluster from 'cluster';

interface ClusterManagerOptions {
  numWorkers: number;
  workerScript: string;
}

function startClusterManager(options: ClusterManagerOptions): {
  reloadWorkers: () => Promise<void>;
} {
  cluster.setupPrimary({ exec: options.workerScript });

  const intentionalExits = new Set<number>();
  let reloading = false;

  for (let i = 0; i < options.numWorkers; i++) {
    cluster.fork();
  }

  cluster.on('exit', (worker) => {
    if (intentionalExits.has(worker.id)) {
      // Expected exit as part of a rolling reload - don't respawn here,
      // reloadWorkers() already forked the replacement itself.
      intentionalExits.delete(worker.id);
      return;
    }
    // Unexpected crash - replace it to keep the pool at full size.
    cluster.fork();
  });

  function forkAndWaitUntilReady(): Promise<import('cluster').Worker> {
    return new Promise((resolve, reject) => {
      const worker = cluster.fork();

      const onListening = (readyWorker: import('cluster').Worker) => {
        if (readyWorker.id !== worker.id) return;
        cluster.removeListener('listening', onListening);
        resolve(worker);
      };

      const onExit = (deadWorker: import('cluster').Worker) => {
        if (deadWorker.id !== worker.id) return;
        cluster.removeListener('exit', onExit);
        cluster.removeListener('listening', onListening);
        reject(new Error('New worker crashed before becoming ready'));
      };

      cluster.on('listening', onListening);
      cluster.on('exit', onExit);
    });
  }

  function disconnectAndWaitUntilExited(worker: import('cluster').Worker): Promise<void> {
    return new Promise((resolve) => {
      intentionalExits.add(worker.id);
      worker.once('exit', () => resolve());
      // disconnect() lets in-flight requests on this worker finish before it exits,
      // unlike worker.kill() which would terminate it immediately.
      worker.disconnect();
    });
  }

  const reloadWorkers = async (): Promise<void> => {
    if (reloading) {
      console.log('Reload already in progress, ignoring duplicate request');
      return;
    }
    reloading = true;

    try {
      // Snapshot current workers before starting - new ones forked during
      // the loop shouldn't be replaced again in this same reload pass.
      const currentWorkers = Object.values(cluster.workers || {}).filter(Boolean) as import('cluster').Worker[];

      for (const oldWorker of currentWorkers) {
        try {
          await forkAndWaitUntilReady();
        } catch (err) {
          // New worker never became ready - abort this step, keep the old
          // worker running rather than disconnecting it with no replacement up.
          console.error('Reload step failed, keeping existing worker:', err);
          continue;
        }
        await disconnectAndWaitUntilExited(oldWorker);
      }
    } finally {
      reloading = false;
    }
  };

  return { reloadWorkers };
}

description.en:
Implement a utility that continuously measures Node.js event loop lag (the delay between when a scheduled timer callback *should* run and when it *actually* runs, which reveals how backed up/blocked the event loop currently is) and emits a warning when lag exceeds a threshold. This is a real production observability tool used to detect CPU-bound code blocking the event loop.

**Requirements:**
- Use `setInterval`/`setTimeout` scheduling combined with `process.hrtime.bigint()` (or `performance.now()`) to measure the actual delay between expected and actual callback firing time
- `startEventLoopMonitor(options)` begins sampling at a configurable interval and returns a handle with a `stop()` method and a `getStats()` method returning `{ current, mean, max, p95 }` lag in milliseconds over a rolling window of recent samples
- Emit a `'lag'` event (via a returned `EventEmitter` or callback option) whenever measured lag exceeds `thresholdMs`
- The monitor's own overhead must be negligible — it must not itself meaningfully contribute to event loop load (e.g. no expensive synchronous work on every tick)
- `stop()` must fully clean up its timer so the process can exit naturally (no dangling handle keeping the event loop alive)

**Function signature:**
typescript
interface MonitorOptions {
  intervalMs?: number;
  thresholdMs?: number;
  windowSize?: number;
}
interface LagStats { current: number; mean: number; max: number; p95: number; }

function startEventLoopMonitor(
  options: MonitorOptions,
  onLag?: (lagMs: number) => void
): { stop: () => void; getStats: () => LagStats }


**Example:**
- `const monitor = startEventLoopMonitor({ intervalMs: 50, thresholdMs: 100 }, (lag) => console.warn('Event loop lag:', lag, 'ms'));`
- Under normal load, `monitor.getStats()` reports lag close to `0`
- If some code runs a synchronous 500ms loop, the next sample after that block reports lag close to 500ms and triggers `onLag`
- `monitor.stop();` — timer cleaned up, process can exit

**Edge cases:**
- Lag measured as a negative or near-zero value due to timer precision quirks — should be clamped to a sane non-negative number, not reported as negative lag
- `getStats()` called before any samples have been collected — return sensible defaults (e.g. all zeros) instead of throwing or returning `NaN`
- Rolling window overflow — old samples must be dropped so `windowSize` bounds memory instead of growing forever over a long-running process
- `stop()` called twice — must not throw on double-clearing the timer

description.ru:
Реализуйте утилиту, непрерывно измеряющую задержку event loop Node.js (разницу между тем, когда запланированный колбэк таймера *должен* сработать, и тем, когда он *реально* сработал, что показывает, насколько сейчас забит/заблокирован event loop) и эмитирующую предупреждение, когда задержка превышает порог. Это реальный production-инструмент observability для обнаружения CPU-bound кода, блокирующего event loop.

**Требования:**
- Используйте планирование через `setInterval`/`setTimeout` в сочетании с `process.hrtime.bigint()` (или `performance.now()`) для измерения реальной задержки между ожидаемым и фактическим временем срабатывания колбэка
- `startEventLoopMonitor(options)` начинает сэмплирование с настраиваемым интервалом и возвращает хендл с методом `stop()` и методом `getStats()`, возвращающим задержку `{ current, mean, max, p95 }` в мс по скользящему окну недавних сэмплов
- Эмитить событие `'lag'` (через возвращённый `EventEmitter` или колбэк-опцию) каждый раз, когда измеренная задержка превышает `thresholdMs`
- Собственные накладные расходы монитора должны быть незначительны — он сам не должен заметно нагружать event loop (например, никакой дорогой синхронной работы на каждый тик)
- `stop()` должен полностью очищать свой таймер, чтобы процесс мог естественно завершиться (без висящего хендла, удерживающего event loop живым)

**Сигнатура функции:**
typescript
interface MonitorOptions {
  intervalMs?: number;
  thresholdMs?: number;
  windowSize?: number;
}
interface LagStats { current: number; mean: number; max: number; p95: number; }

function startEventLoopMonitor(
  options: MonitorOptions,
  onLag?: (lagMs: number) => void
): { stop: () => void; getStats: () => LagStats }


**Пример:**
- `const monitor = startEventLoopMonitor({ intervalMs: 50, thresholdMs: 100 }, (lag) => console.warn('Event loop lag:', lag, 'ms'));`
- При нормальной нагрузке `monitor.getStats()` показывает задержку близкую к `0`
- Если какой-то код выполняет синхронный цикл на 500мс, следующий сэмпл после этого блока показывает задержку близкую к 500мс и триггерит `onLag`
- `monitor.stop();` — таймер очищен, процесс может завершиться

**Граничные случаи:**
- Задержка измерена как отрицательное или почти нулевое значение из-за особенностей точности таймера — должна быть ограничена снизу разумным неотрицательным числом, а не отражена как отрицательная задержка
- `getStats()` вызван до сбора каких-либо сэмплов — вернуть разумные значения по умолчанию (например, все нули), а не бросать исключение или возвращать `NaN`
- Переполнение скользящего окна — старые сэмплы должны отбрасываться, чтобы `windowSize` ограничивал память, а не рос бесконечно на долгоживущем процессе
- `stop()` вызван дважды — не должен бросать исключение при повторной очистке таймера

