solution:
interface MonitorOptions {
  intervalMs?: number;
  thresholdMs?: number;
  windowSize?: number;
}
interface LagStats { current: number; mean: number; max: number; p95: number; }

function startEventLoopMonitor(
  options: MonitorOptions = {},
  onLag?: (lagMs: number) => void
): { stop: () => void; getStats: () => LagStats } {
  const intervalMs = options.intervalMs ?? 100;
  const thresholdMs = options.thresholdMs ?? 100;
  const windowSize = options.windowSize ?? 50;

  const samples: number[] = [];
  let stopped = false;
  let timer: NodeJS.Timeout;
  let expectedNext = Date.now() + intervalMs;

  const recordSample = (lagMs: number) => {
    // Timer precision can occasionally report a tiny negative value even when
    // nothing was actually blocking - clamp instead of polluting stats with
    // meaningless negative "lag".
    const clamped = Math.max(0, lagMs);

    samples.push(clamped);
    if (samples.length > windowSize) {
      samples.shift();
    }

    if (clamped > thresholdMs && onLag) {
      onLag(clamped);
    }
  };

  const tick = () => {
    if (stopped) return;

    const now = Date.now();
    const lag = now - expectedNext;
    recordSample(lag);

    expectedNext = now + intervalMs;
    timer = setTimeout(tick, intervalMs);
    // Let the process exit naturally if this is the only thing keeping it alive
    timer.unref?.();
  };

  timer = setTimeout(tick, intervalMs);
  timer.unref?.();

  const getStats = (): LagStats => {
    if (samples.length === 0) {
      return { current: 0, mean: 0, max: 0, p95: 0 };
    }

    const current = samples[samples.length - 1];
    const sum = samples.reduce((a, b) => a + b, 0);
    const mean = sum / samples.length;
    const max = Math.max(...samples);

    const sorted = [...samples].sort((a, b) => a - b);
    const p95Index = Math.min(sorted.length - 1, Math.floor(sorted.length * 0.95));
    const p95 = sorted[p95Index];

    return { current, mean, max, p95 };
  };

  const stop = () => {
    stopped = true;
    clearTimeout(timer);
  };

  return { stop, getStats };
}

