    this.name = name;
    this.maxConcurrent = maxConcurrent;
    this.maxQueueSize = maxQueueSize;
  }

  execute<T>(fn: () => Promise<T>): Promise<T> {
    // If active < maxConcurrent: run immediately
    // Else if queue.length < maxQueueSize: queue and wait for a slot
    // Else: reject immediately with BulkheadRejectedError
    // Always free the slot (active--) when fn settles, then start the next queued call if any
    return Promise.reject(new Error('not implemented'));
  }

  getStats(): BulkheadStats {
    return { active: this.active, queued: this.queue.length, rejected: this.rejectedCount };
  }
}

