class BulkheadRejectedError extends Error {
  constructor(name: string) {
    super(`Bulkhead '${name}' rejected the call: pool and queue are full`);
    this.name = 'BulkheadRejectedError';
  }
}

interface BulkheadStats { active: number; queued: number; rejected: number; }

class Bulkhead {
  private name: string;
  private maxConcurrent: number;
  private maxQueueSize: number;
  private active: number = 0;
  private queue: Array<() => void> = [];
  private rejectedCount: number = 0;

  constructor(name: string, maxConcurrent: number, maxQueueSize: number) {
    this.name = name;
    this.maxConcurrent = maxConcurrent;
    this.maxQueueSize = maxQueueSize;
  }

  execute<T>(fn: () => Promise<T>): Promise<T> {
    if (this.active < this.maxConcurrent) {
      return this.runNow(fn);
    }

    if (this.queue.length < this.maxQueueSize) {
      return new Promise<T>((resolve, reject) => {
        this.queue.push(() => {
          this.runNow(fn).then(resolve, reject);
        });
      });
    }

    this.rejectedCount++;
    return Promise.reject(new BulkheadRejectedError(this.name));
  }

  private async runNow<T>(fn: () => Promise<T>): Promise<T> {
    this.active++;
    try {
      return await fn();
    } finally {
      this.active--;
      this.dequeueNext();
    }
  }

  private dequeueNext(): void {
    if (this.queue.length === 0) return;
    if (this.active >= this.maxConcurrent) return;
    const next = this.queue.shift()!;
    next();
  }

  getStats(): BulkheadStats {
    return { active: this.active, queued: this.queue.length, rejected: this.rejectedCount };
  }
}

