class Semaphore {
  private totalCapacity: number;
  private available: number;
  private waiters: Array<{ weight: number; resolve: () => void }> = [];

  constructor(totalCapacity: number) {
    this.totalCapacity = totalCapacity;
    this.available = totalCapacity;
  }

  acquire(weight: number): Promise<void> {
    // Reject immediately if weight > totalCapacity (can never be satisfied)
    // If enough is available right now, reserve it and resolve immediately
    // Otherwise queue (FIFO) and wait to be granted
    return Promise.reject(new Error('not implemented'));
  }

  release(weight: number): void {
    // Return weight to available capacity
    // Then try to grant the front of the queue (strict FIFO - the queue head
    // blocks everyone behind it, even if a later request would fit)
  }

  async runExclusive<T>(weight: number, fn: () => Promise<T>): Promise<T> {
    await this.acquire(weight);
    try {
      return await fn();
    } finally {
      this.release(weight);
    }
  }
}

solution:
class Semaphore {
  private totalCapacity: number;
  private available: number;
  private waiters: Array<{ weight: number; resolve: () => void }> = [];

  constructor(totalCapacity: number) {
    this.totalCapacity = totalCapacity;
    this.available = totalCapacity;
  }

  acquire(weight: number): Promise<void> {
    if (weight > this.totalCapacity) {
      return Promise.reject(
        new Error(`Requested weight ${weight} exceeds total capacity ${this.totalCapacity}`)
      );
    }

    if (this.waiters.length === 0 && weight <= this.available) {
      this.available -= weight;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waiters.push({ weight, resolve });
    });
  }

  release(weight: number): void {
    this.available += weight;
    this.grantWaiters();
  }

  private grantWaiters(): void {
    // Strict FIFO: only ever look at the front of the queue. If the front
    // request doesn't fit yet, stop - do NOT skip ahead to a smaller request
    // further back, even if it would fit. This guarantees no starvation for
    // the earliest waiter at the cost of smaller later requests waiting
    // behind a larger one that hasn't been satisfied yet.
    while (this.waiters.length > 0 && this.waiters[0].weight <= this.available) {
      const next = this.waiters.shift()!;
      this.available -= next.weight;
      next.resolve();
    }
  }

  async runExclusive<T>(weight: number, fn: () => Promise<T>): Promise<T> {
    await this.acquire(weight);
    try {
      return await fn();
    } finally {
      this.release(weight);
    }
  }
}

