class VersionConflictError extends Error {
  constructor(key: string, expected: number, actual: number) {
    super(`Version conflict for '${key}': expected ${expected}, but current version is ${actual}`);
    this.name = 'VersionConflictError';
  }
}

interface Rec<V> { value: V; version: number; }

class OptimisticStore<V> {
  private store: Map<string, Rec<V>> = new Map();

  set(key: string, value: V): void {
    this.store.set(key, { value, version: 0 });
  }

  get(key: string): Rec<V> | undefined {
    const rec = this.store.get(key);
    return rec ? { ...rec } : undefined;
  }

  update(key: string, expectedVersion: number, newValue: V): number {
    // Check current version matches expectedVersion; throw VersionConflictError if not
    // Otherwise write newValue and increment version, return new version
    return 0;
  }

  updateWithRetry(key: string, updateFn: (current: V) => V, maxRetries: number): V {
    // Loop up to maxRetries: read current, compute updateFn(current.value),
    // attempt update(), return on success, retry on VersionConflictError
    // Throw after exhausting retries
    throw new Error('not implemented');
  }
}

solution:
class VersionConflictError extends Error {
  constructor(key: string, expected: number, actual: number) {
    super(`Version conflict for '${key}': expected ${expected}, but current version is ${actual}`);
    this.name = 'VersionConflictError';
  }
}

interface Rec<V> { value: V; version: number; }

class OptimisticStore<V> {
  private store: Map<string, Rec<V>> = new Map();

  set(key: string, value: V): void {
    this.store.set(key, { value, version: 0 });
  }

  get(key: string): Rec<V> | undefined {
    const rec = this.store.get(key);
    // Return a copy, not the internal reference, so callers can't mutate
    // stored state directly and bypass the version-checked update() path.
    return rec ? { ...rec } : undefined;
  }

  update(key: string, expectedVersion: number, newValue: V): number {
    const current = this.store.get(key);
    if (!current) {
      throw new Error(`Cannot update nonexistent key: ${key}`);
    }

    // The check and the write below happen with no 'await' between them,
    // so no other synchronous call can interleave and observe a half-updated
    // state - JS's single-threaded execution model makes this section
    // effectively atomic without needing an explicit lock.
    if (current.version !== expectedVersion) {
      throw new VersionConflictError(key, expectedVersion, current.version);
    }

    const newVersion = current.version + 1;
    this.store.set(key, { value: newValue, version: newVersion });
    return newVersion;
  }

  updateWithRetry(key: string, updateFn: (current: V) => V, maxRetries: number): V {
    for (let attempt = 0; attempt <= maxRetries; attempt++) {
      const current = this.get(key);
      if (!current) {
        throw new Error(`Cannot update nonexistent key: ${key}`);
      }

      const newValue = updateFn(current.value);

      try {
        this.update(key, current.version, newValue);
        return newValue;
      } catch (err) {
        if (!(err instanceof VersionConflictError)) throw err;
        // Lost the race - loop again to re-read fresh version/value and retry,
        // unless we've exhausted our attempts.
        if (attempt === maxRetries) {
          throw new Error(`Failed to update '${key}' after ${maxRetries} retries due to version conflicts`);
        }
      }
    }

    // Unreachable, but keeps TypeScript's control-flow analysis satisfied
    throw new Error('unreachable');
  }
}

