type Handler = (...args: any[]) => void;

interface Subscription {
  ref: WeakRef<object>;
  handler: Handler;
}

class WeakEventBus {
  private subscriptions: Set<Subscription> = new Set();
  private registry: FinalizationRegistry<Subscription>;

  constructor() {
    // Set up a FinalizationRegistry to opportunistically remove a
    // subscription's bookkeeping entry once its target is collected
    this.registry = new FinalizationRegistry((heldValue) => {
      // Remove the corresponding subscription from this.subscriptions
    });
  }

  subscribe(target: object, handler: Handler): void {
    // Create a WeakRef to target, store { ref, handler } in subscriptions
    // Register target with the FinalizationRegistry, passing the subscription
    // object as the held value so the cleanup callback can find and remove it
  }

  emit(...args: any[]): void {
    // For each subscription, dereference the WeakRef
    // If still alive, call handler(...args)
    // If dead, it will eventually be cleaned up by the registry - don't call it
  }

  getActiveSubscriptionCount(): number {
    // Best-effort count of subscriptions whose target currently dereferences successfully
    return 0;
  }
}

solution:
type Handler = (...args: any[]) => void;

interface Subscription {
  ref: WeakRef<object>;
  handler: Handler;
}

class WeakEventBus {
  private subscriptions: Set<Subscription> = new Set();
  private registry: FinalizationRegistry<Subscription>;

  constructor() {
    this.registry = new FinalizationRegistry((heldValue) => {
      // heldValue is the exact Subscription object passed to `register` below.
      // Note: this callback timing is NOT deterministic - it may run long
      // after the target actually became unreachable, or in rare cases
      // (e.g. abrupt process exit) not run at all. It's an optimization to
      // reclaim bookkeeping memory over time, not a guarantee.
      this.subscriptions.delete(heldValue);
    });
  }

  subscribe(target: object, handler: Handler): void {
    const subscription: Subscription = {
      ref: new WeakRef(target),
      handler,
    };
    this.subscriptions.add(subscription);
    // Register target for cleanup notification; pass the subscription object
    // itself as the held value so the FinalizationRegistry callback can find
    // and remove exactly this entry without re-scanning the whole set.
    this.registry.register(target, subscription, subscription);
  }

  emit(...args: any[]): void {
    for (const subscription of this.subscriptions) {
      const target = subscription.ref.deref();
      if (target === undefined) {
        // Target was already collected but the FinalizationRegistry callback
        // hasn't run yet (timing isn't guaranteed) - skip silently rather
        // than calling a handler for a dead target.
        continue;
      }
      subscription.handler(...args);
    }
  }

  getActiveSubscriptionCount(): number {
    let count = 0;
    for (const subscription of this.subscriptions) {
      if (subscription.ref.deref() !== undefined) count++;
    }
    return count;
  }
}
